class Node:
    def __init__(self, val=0, neighbors=None):
        self.val = val
        self.neighbors = neighbors if neighbors is not None else []

class Solution:
    def cloneGraph(self, node: 'Node') -> 'Node':
        if not node:
            return None

        # Dictionary to store visited nodes and their clones
        # original_node -> cloned_node
        visited = {}

        def dfs(original_node):
            # If the node has already been visited/cloned, return its clone
            if original_node in visited:
                return visited[original_node]

            # Create a clone for the current node
            cloned_node = Node(original_node.val)

            # Mark it as visited and store its clone
            visited[original_node] = cloned_node

            # Recurse for all neighbors and connect them to the cloned node
            for neighbor in original_node.neighbors:
                cloned_node.neighbors.append(dfs(neighbor))

            return cloned_node

        return dfs(node)
